/* ══════════════════════════════
   STATE
══════════════════════════════ */
let cart          = [];
let orderType     = 'Dine In';
let activeCategory = 'coffee';
let orderNum      = Math.floor(Math.random() * 900) + 100;


/* ══════════════════════════════
   CLOCK
══════════════════════════════ */
function updateClock() {
  document.getElementById('clock').textContent =
    new Date().toLocaleTimeString('en-PH', { hour: '2-digit', minute: '2-digit' });
}
setInterval(updateClock, 1000);
updateClock();


/* ══════════════════════════════
   BUILD MENU
══════════════════════════════ */
function buildMenu() {
  const tabs      = document.getElementById('tabs');
  const container = document.getElementById('menu-container');

  menu.forEach(cat => {
    // ── Tab button ──
    const btn = document.createElement('button');
    btn.className = 'tab-btn' + (cat.id === activeCategory ? ' active' : '');
    btn.textContent = cat.label;
    btn.onclick = () => switchCategory(cat.id);
    tabs.appendChild(btn);

    // ── Section ──
    const section = document.createElement('div');
    section.className = 'menu-section' + (cat.id === activeCategory ? ' visible' : '');
    section.id = 'sec-' + cat.id;

    section.innerHTML = `
      <div class="section-header">
        <div class="section-title">${cat.label}</div>
        <div class="section-line"></div>
      </div>
    `;

    const grid = document.createElement('div');
    grid.className = 'items-grid';
    cat.items.forEach(item => grid.appendChild(buildItemCard(item)));

    section.appendChild(grid);
    container.appendChild(section);
  });
}

function buildItemCard(item) {
  const card = document.createElement('div');
  const hasVariants = item.hot !== undefined;
  card.className = 'item-card' + (hasVariants ? ' has-variants' : '');
  card.id = 'card-' + item.id;

  const price = item.price || item.hot || item.iced;

  if (hasVariants) {
    // Build hot/iced variant buttons
    let variantsHtml = '<div class="variants-row">';
    if (item.hot)  variantsHtml += `<button class="var-btn" onclick="addVariant(event,'${item.id}','Hot',${item.hot},'${item.image}','${item.name}')">🔥 HOT<span class="var-price">₱${item.hot}</span></button>`;
    if (item.iced) variantsHtml += `<button class="var-btn" onclick="addVariant(event,'${item.id}','Iced',${item.iced},'${item.image}','${item.name}')">🧊 ICED<span class="var-price">₱${item.iced}</span></button>`;
    variantsHtml += '</div>';

    card.innerHTML = `
      <div class="cart-badge" id="badge-${item.id}">0</div>
      <div class="item-image">${item.image ? `<img src="${item.image}" alt="${item.name}">` : '<div class="image-placeholder">Image<br>150x150</div>'}</div>
      <div class="item-name">${item.name}</div>
      ${item.sub ? `<div class="item-sub">${item.sub}</div>` : ''}
      ${variantsHtml}
    `;
  } else {
    card.innerHTML = `
      <div class="cart-badge" id="badge-${item.id}">0</div>
      <div class="item-image">${item.image ? `<img src="${item.image}" alt="${item.name}">` : '<div class="image-placeholder">Image<br>150x150</div>'}</div>
      <div class="item-name">${item.name}</div>
      ${item.sub ? `<div class="item-sub">${item.sub}</div>` : ''}
      <div class="item-footer">
        <div class="item-price">₱${price}</div>
        <button class="add-btn" onclick="addItem(event,'${item.id}',${price},'${item.image}','${item.name}')">+</button>
      </div>
    `;
  }

  return card;
}


/* ══════════════════════════════
   CATEGORY NAVIGATION
══════════════════════════════ */
function switchCategory(id) {
  activeCategory = id;

  document.querySelectorAll('.tab-btn').forEach((btn, i) => {
    btn.classList.toggle('active', menu[i].id === id);
  });

  document.querySelectorAll('.menu-section').forEach(sec => {
    sec.classList.toggle('visible', sec.id === 'sec-' + id);
  });

  document.querySelector('.menu-panel').scrollTop = 0;
}


/* ══════════════════════════════
   ADD TO CART
══════════════════════════════ */
function addItem(e, id, price, image, name, variant = '') {
  if (e) e.stopPropagation();

  const key      = id + (variant ? '_' + variant : '');
  const existing = cart.find(c => c.key === key);

  if (existing) {
    existing.qty++;
  } else {
    cart.push({ key, id, name, image, price, variant, qty: 1 });
  }

  updateCart();
  pulseCard(id);
}

function addVariant(e, id, variant, price, image, name) {
  if (e) e.stopPropagation();
  addItem(null, id, price, image, name, variant);
}

function pulseCard(id) {
  const card = document.getElementById('card-' + id);
  if (!card) return;
  card.style.transform = 'scale(0.97)';
  setTimeout(() => { card.style.transform = ''; }, 150);
}


/* ══════════════════════════════
   ORDER TYPE
══════════════════════════════ */
function setOrderType(btn, type) {
  orderType = type;
  document.querySelectorAll('.ot-btn').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
}


/* ══════════════════════════════
   UPDATE CART UI
══════════════════════════════ */
function updateCart() {
  const container = document.getElementById('cart-items');
  const total     = cart.reduce((sum, c) => sum + c.price * c.qty, 0);
  const count     = cart.reduce((sum, c) => sum + c.qty, 0);

  // Update item card badges
  const itemTotals = {};
  cart.forEach(c => {
    itemTotals[c.id] = (itemTotals[c.id] || 0) + c.qty;
  });

  document.querySelectorAll('.item-card').forEach(card => {
    const id  = card.id.replace('card-', '');
    const qty = itemTotals[id] || 0;
    const badge = card.querySelector('.cart-badge');
    if (badge) badge.textContent = qty;
    card.classList.toggle('in-cart', qty > 0);
  });

  // Update summary
  document.getElementById('order-count').textContent = count + ' item' + (count !== 1 ? 's' : '');
  document.getElementById('subtotal').textContent    = '₱' + total.toFixed(2);
  document.getElementById('total').textContent       = '₱' + total.toFixed(2);
  document.getElementById('checkout-btn').disabled   = cart.length === 0;
  document.getElementById('clear-btn').style.display = cart.length ? '' : 'none';

  // Render cart items
  if (cart.length === 0) {
    container.innerHTML = `
      <div class="cart-empty">
        <div class="cart-empty-icon">☕</div>
        <div class="cart-empty-text">Your order is empty</div>
      </div>`;
    return;
  }

  container.innerHTML = '';
  cart.forEach(item => {
    const div = document.createElement('div');
    div.className = 'cart-item';
    div.innerHTML = `
      <div class="ci-image">${item.image ? `<img src="${item.image}" alt="${item.name}">` : '📦'}</div>
      <div class="ci-info">
        <div class="ci-name">${item.name}</div>
        <div class="ci-variant">${item.variant || 'Regular'}</div>
        <div class="ci-controls">
          <button class="qty-btn minus" onclick="changeQty('${item.key}', -1)">−</button>
          <span class="ci-qty">${item.qty}</span>
          <button class="qty-btn" onclick="changeQty('${item.key}', 1)">+</button>
        </div>
      </div>
      <div class="ci-price">₱${item.price * item.qty}</div>
    `;
    container.appendChild(div);
  });
}


/* ══════════════════════════════
   CHANGE QUANTITY
══════════════════════════════ */
function changeQty(key, delta) {
  const idx = cart.findIndex(c => c.key === key);
  if (idx === -1) return;

  cart[idx].qty += delta;
  if (cart[idx].qty <= 0) cart.splice(idx, 1);

  updateCart();
}


/* ══════════════════════════════
   CLEAR CART
══════════════════════════════ */
function clearCart() {
  if (!confirm('Clear all items?')) return;
  cart = [];
  updateCart();
}


/* ══════════════════════════════
   CHECKOUT
══════════════════════════════ */
function checkout() {
  const modal = document.getElementById('modal');
  const total = cart.reduce((sum, c) => sum + c.price * c.qty, 0);
  orderNum++;

  document.getElementById('modal-order-num').textContent =
    '#' + String(orderNum).padStart(3, '0');
  document.getElementById('modal-type').textContent =
    orderType + ' · Please wait for your order';

  const itemsEl = document.getElementById('modal-items');
  itemsEl.innerHTML =
    cart.map(c =>
      `<div class="modal-item">
        <strong>${c.name} ${c.variant ? '(' + c.variant + ')' : ''} x${c.qty}</strong>
        <span>₱${c.price * c.qty}</span>
      </div>`
    ).join('')+
    `<div class="modal-total"><span>TOTAL</span><span>₱${total}</span></div>`;

  modal.classList.add('open');
}


/* ══════════════════════════════
   NEW ORDER (reset)
══════════════════════════════ */
function newOrder() {
  document.getElementById('modal').classList.remove('open');
  cart = [];
  updateCart();
}


/* ══════════════════════════════
   INIT
══════════════════════════════ */
buildMenu();